import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance_metric(from_pos, to_pos):
        return np.linalg.norm(from_pos - to_pos)

    # Identifying zones based on customer location clustering and time proximity
    centroids = np.mean(unvisited_customers, axis=0)  # This is a simple placeholder for actual clustering
    zones = {0: []}
    for idx, customer_pos in enumerate(unvisited_customers):
        if distance_metric(customer_pos, centroids) < 50:  # Arbitrary distance threshold for zone creation
            zones[0].append((idx, customer_pos, time_windows[idx]))

    # Evaluate best customer per zone considering current truck location, time, and speed
    min_score = float('inf')
    best_node = None
    for zone in zones.values():
        for customer_idx, customer_pos, (window_start, window_end) in zone:
            travel_time = distance_metric(cur_truck_pos, customer_pos) / truck_speed
            arrival_time = current_time + travel_time
            waiting_time = max(0, window_start - arrival_time)

            total_time_cost = travel_time + waiting_time

            if arrival_time > window_end:
                continue  # Skipping as not feasible

            # Score calculation - prioritize minimizing overall time cost adjusted by how critical the timing window is
            score = total_time_cost + (window_end - arrival_time) * 0.1  # Time sensitivity factor

            if score < min_score:
                min_score = score
                best_node = customer_idx

    return best_node

