def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(coord1, coord2):
        return np.linalg.norm(coord1 - coord2)

    def time_to_reach(start_pos, end_pos, speed):
        distance = euclidean_distance(start_pos, end_pos)
        return distance / speed

    remaining_times = []
    num_customers = len(unvisited_customers)

    for index, customer in enumerate(unvisited_customers):
        travel_time = time_to_reach(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[index]

        # Calculate how fitting the arrival time is within the time window
        if arrival_time < start_window:
            wait_time = start_window - arrival_time
        elif arrival_time > end_window:
            wait_time = arrival_time - end_window
        else:
            wait_time = 0

        urgency = end_window - current_time  # Less time till end of window, more urgent
        score = wait_time + (0.1 * urgency)  # Minimize wait time, consider urgency with less weigh
        remaining_times.append((score, index))

    # Sort primarily by score then by arrival time within window
    remaining_times.sort()

    # Find the best node index if it exists, otherwise return None to wait
    if remaining_times:
        best_node = remaining_times[0][1]
    else:
        best_node = None

    return best_node

